<span class="line"><span style="color:#E06C75;">TOOLCHAIN</span><span style="color:#56B6C2;">=</span><span style="color:#E06C75;">$NDK</span><span style="color:#98C379;">/toolchains/llvm/prebuilt/linux-x86_64</span></span>
